  2	import { IRow, IAction, ThProps, IRowData } from '@patternfly/react-table';
  3	import { kialiStyle } from 'styles/StyleUtils';
  4	import { PFColors } from '../../Pf/PfColors';
  5	import {
  6	  EmptyState,
  7	  EmptyStateBody,
  8	  EmptyStateVariant,
  9	  TooltipPosition,
 10	  EmptyStateHeader
 11	} from '@patternfly/react-core';
 12	import { WorkloadWeight } from '../TrafficShifting';
 13	import { Abort, Delay, HTTPRetry } from '../../../types/IstioObjects';
 14	import { PFBadge, PFBadges } from 'components/Pf/PfBadges';
 15	import { ROUTE_RULES_TOOLTIP, wizardTooltip } from '../WizardHelp';
 16	import { SimpleTable } from 'components/Table/SimpleTable';
 17	import { t } from 'utils/I18nUtils';
 18	
 19	export enum MOVE_TYPE {
 20	  UP,
 21	  DOWN
 22	}
 23	
 24	export type Rule = {
 25	  abort?: Abort;
 26	  delay?: Delay;
 27	  matches: string[];
 28	  retries?: HTTPRetry;
 29	  timeout?: string;
 30	  workloadWeights: WorkloadWeight[];
 31	};
 32	
 33	type RulesProps = {
 34	  onMoveRule: (index: number, move: MOVE_TYPE) => void;
 35	  onRemoveRule: (index: number) => void;
 36	  rules: Rule[];
 37	};
 38	
 39	const validationStyle = kialiStyle({
 40	  marginTop: '0.75rem',
 41	  color: PFColors.Red100
 42	});
 43	
 44	const noRulesStyle = kialiStyle({
 45	  marginTop: '0.75rem',
 46	  color: PFColors.Red100,
 47	  textAlign: 'center',
 48	  width: '100%'
 49	});
 50	
 51	export const Rules: React.FC<RulesProps> = (props: RulesProps) => {
 52	  const matchAllIndex = (rules: Rule[]): number => {
 53	    let matchAll = -1;
 54	
 55	    for (let index = 0; index < rules.length; index++) {
 56	      const rule = rules[index];
 57	
 58	      if (rule.matches.length === 0) {
 59	        matchAll = index;
 60	        break;
 61	      }
 62	    }
 63	
 64	    return matchAll;
 65	  };
 66	
 67	  const actionResolver = (_rowData: IRowData, rowIndex: number): IAction[] => {
 68	    const removeAction = {
 69	      title: t('Remove Rule'),
 70	      onClick: () => props.onRemoveRule(rowIndex)
 71	    };
 72	
 73	    const moveUpAction = {
 74	      title: t('Move Up'),
 75	      onClick: () => props.onMoveRule(rowIndex, MOVE_TYPE.UP)
 76	    };
 77	
 78	    const moveDownAction = {
 79	      title: t('Move Down'),
 80	      onClick: () => props.onMoveRule(rowIndex, MOVE_TYPE.DOWN)
 81	    };
 82	
 83	    const actions: IAction[] = [];
 84	
 85	    if (props.rules.length > 0) {
 86	      actions.push(removeAction);
 87	    }
 88	
 89	    if (rowIndex > 0) {
 90	      actions.push(moveUpAction);
 91	    }
 92	
 93	    if (rowIndex + 1 < props.rules.length) {
 94	      actions.push(moveDownAction);
 95	    }
 96	
 97	    return actions;
 98	  };
 99	
100	  const columns: ThProps[] = [
101	    {
102	      title: t('Rule order'),
103	      width: 10
104	    },
105	    {
106	      title: t('Request Matching')
107	    },
108	    {
109	      title: t('Route To')
110	    }
111	  ];
112	
113	  let isValid = true;
114	
115	  const matchAll: number = matchAllIndex(props.rules);
116	
117	  const noRules: React.ReactNode = (
118	    <EmptyState variant={EmptyStateVariant.full}>
119	      <EmptyStateHeader titleText={t('No Route Rules defined')} headingLevel="h5" />
120	      <EmptyStateBody className={noRulesStyle}>{t('A Request Routing scenario needs at least a Route Rule')}</EmptyStateBody>
121	    </EmptyState>
122	  );
123	
124	  const routeRules: IRow[] = props.rules.map((rule, order) => {
125	    isValid = matchAll === -1 || order <= matchAll;
126	
127	    return {
128	      cells: [
129	        <>{order + 1}</>,
130	        <>
131	          {rule.matches.length === 0
132	            ? 'Any request'
133	            : rule.matches.map((match, i) => <div key={`match_${i}`}>{match}</div>)}
134	          {!isValid && (
135	            <div className={validationStyle}>
136	              {t('Match \'Any request\' is defined in a previous rule.')}
137	              <br />
138	              {t('This rule is not accessible.')}
139	            </div>
140	          )}
141	        </>,
142	        <>
143	          <div key={`ww_${order}`}>
144	            {rule.workloadWeights
145	              .filter(wk => !wk.mirrored)
146	              .map((wk, i) => {
147	                return (
148	                  <div key={`wk_${order}_${wk.name}_${i}`}>
149	                    <PFBadge badge={PFBadges.Workload} position={TooltipPosition.top} />
150	                    {wk.name} ({wk.weight}% routed traffic)
151	                  </div>
152	                );
153	              })}
154	
155	            {rule.workloadWeights
156	              .filter(wk => wk.mirrored)
157	              .map((wk, i) => {
158	                return (
159	                  <div key={`wk_mirrored_${order}_${wk.name}_${i}`}>
160	                    <PFBadge badge={PFBadges.MirroredWorkload} position={TooltipPosition.top} />
161	                    {wk.name} ({wk.weight}% mirrored traffic)
162	                  </div>
163	                );
164	              })}
165	          </div>
166	
167	          {rule.delay && (
168	            <div key={`delay_${order}`}>
169	              <PFBadge badge={PFBadges.FaultInjectionDelay} position={TooltipPosition.top} />
170	              {rule.delay.percentage?.value}% requests delayed ({rule.delay.fixedDelay})
171	            </div>
172	          )}
173	
174	          {rule.abort && (
175	            <div key={`abort_${order}`}>
176	              <PFBadge badge={PFBadges.FaultInjectionAbort} position={TooltipPosition.top} />
177	              {rule.abort.percentage?.value}% requests aborted (HTTP Status {rule.abort.httpStatus})
178	            </div>
179	          )}
180	
181	          {rule.timeout && (
182	            <div key={`timeout_${order}`}>
183	              <PFBadge badge={PFBadges.RequestTimeout} position={TooltipPosition.top} />
184	              timeout ({rule.timeout})
185	            </div>
186	          )}
187	
188	          {rule.retries && (
189	            <div key={`retries_${order}`}>
190	              <PFBadge badge={PFBadges.RequestRetry} position={TooltipPosition.top} />
191	              {rule.retries.attempts} attempts with timeout ({rule.timeout})
192	            </div>
193	          )}
194	        </>
195	      ]
196	    };
197	  });
198	
199	  return (
200	    <>
201	      <div>
202	        <span>{t('Route Rules')}</span>
203	        {wizardTooltip(ROUTE_RULES_TOOLTIP)}
204	      </div>
205	
206	      <SimpleTable
207	        label="Rules Created"
208	        columns={columns}
209	        rows={routeRules}
210	        actionResolver={actionResolver}
211	        emptyState={noRules}
212	        verticalAlign="middle"
213	      />
214	    </>
215	  );
216	};

