 50	export const Rules: React.FC<RulesProps> = (props: RulesProps) => {
 51	  const matchAllIndex = (rules: Rule[]): number => {
 52	    let matchAll = -1;
 53	
 54	    for (let index = 0; index < rules.length; index++) {
 55	      const rule = rules[index];
 56	
 57	      if (rule.matches.length === 0) {
 58	        matchAll = index;
 59	        break;
 60	      }
 61	    }
 62	
 63	    return matchAll;
 64	  };
 65	
 66	  const actionResolver = (_rowData: IRowData, rowIndex: number): IAction[] => {
 67	    const removeAction = {
 68	      title: t('Remove Rule'),
 69	      onClick: () => props.onRemoveRule(rowIndex)
 70	    };
 71	
 72	    const moveUpAction = {
 73	      title: t('Move Up'),
 74	      onClick: () => props.onMoveRule(rowIndex, MOVE_TYPE.UP)
 75	    };
 76	
 77	    const moveDownAction = {
 78	      title: t('Move Down'),
 79	      onClick: () => props.onMoveRule(rowIndex, MOVE_TYPE.DOWN)
 80	    };
 81	
 82	    const actions: IAction[] = [];
 83	
 84	    if (props.rules.length > 0) {
 85	      actions.push(removeAction);
 86	    }
 87	
 88	    if (rowIndex > 0) {
 89	      actions.push(moveUpAction);
 90	    }
 91	
 92	    if (rowIndex + 1 < props.rules.length) {
 93	      actions.push(moveDownAction);
 94	    }
 95	
 96	    return actions;
 97	  };
 98	
 99	  const columns: ThProps[] = [
100	    {
101	      title: t('Rule order'),
102	      width: 10
103	    },
104	    {
105	      title: t('Request Matching')
106	    },
107	    {
108	      title: t('Route To')
109	    }
110	  ];
111	
112	  let isValid = true;
113	
114	  const matchAll: number = matchAllIndex(props.rules);
115	
116	  const noRules: React.ReactNode = (
117	    <EmptyState variant={EmptyStateVariant.full} titleText={t('No Route Rules defined')} headingLevel="h5">
118	      <EmptyStateBody className={noRulesStyle}>{t('A Request Routing scenario needs at least a Route Rule')}</EmptyStateBody>
119	    </EmptyState>
120	  );
121	
122	  const routeRules: IRow[] = props.rules.map((rule, order) => {
123	    isValid = matchAll === -1 || order <= matchAll;
124	
125	    return {
126	      cells: [
127	        <>{order + 1}</>,
128	        <>
129	          {rule.matches.length === 0
130	            ? 'Any request'
131	            : rule.matches.map((match, i) => <div key={`match_${i}`}>{match}</div>)}
132	          {!isValid && (
133	            <div className={validationStyle}>
134	              {t('Match \'Any request\' is defined in a previous rule.')}
135	              <br />
136	              {t('This rule is not accessible.')}
137	            </div>
138	          )}
139	        </>,
140	        <>
141	          <div key={`ww_${order}`}>
142	            {rule.workloadWeights
143	              .filter(wk => !wk.mirrored)
144	              .map((wk, i) => {
145	                return (
146	                  <div key={`wk_${order}_${wk.name}_${i}`}>
147	                    <PFBadge badge={PFBadges.Workload} position={TooltipPosition.top} />
148	                    {wk.name} ({wk.weight}% routed traffic)
149	                  </div>
150	                );
151	              })}
152	
153	            {rule.workloadWeights
154	              .filter(wk => wk.mirrored)
155	              .map((wk, i) => {
156	                return (
157	                  <div key={`wk_mirrored_${order}_${wk.name}_${i}`}>
158	                    <PFBadge badge={PFBadges.MirroredWorkload} position={TooltipPosition.top} />
159	                    {wk.name} ({wk.weight}% mirrored traffic)
160	                  </div>
161	                );
162	              })}
163	          </div>
164	
165	          {rule.delay && (
166	            <div key={`delay_${order}`}>
167	              <PFBadge badge={PFBadges.FaultInjectionDelay} position={TooltipPosition.top} />
168	              {rule.delay.percentage?.value}% requests delayed ({rule.delay.fixedDelay})
169	            </div>
170	          )}
171	
172	          {rule.abort && (
173	            <div key={`abort_${order}`}>
174	              <PFBadge badge={PFBadges.FaultInjectionAbort} position={TooltipPosition.top} />
175	              {rule.abort.percentage?.value}% requests aborted (HTTP Status {rule.abort.httpStatus})
176	            </div>
177	          )}
178	
179	          {rule.timeout && (
180	            <div key={`timeout_${order}`}>
181	              <PFBadge badge={PFBadges.RequestTimeout} position={TooltipPosition.top} />
182	              timeout ({rule.timeout})
183	            </div>
184	          )}
185	
186	          {rule.retries && (
187	            <div key={`retries_${order}`}>
188	              <PFBadge badge={PFBadges.RequestRetry} position={TooltipPosition.top} />
