197	  return (
198	    <>
199	      <div>
200	        <span>{t('Route Rules')}</span>
201	        {wizardTooltip(ROUTE_RULES_TOOLTIP)}
202	      </div>
203	
204	      <SimpleTable
205	        label="Rules Created"
206	        columns={columns}
207	        rows={routeRules}
208	        actionResolver={actionResolver}
209	        emptyState={noRules}
210	        verticalAlign="middle"
211	      />
212	    </>
213	  );
214	};
